// Annotation sur les paramètres et le retour
function additionner(a: number, b: number): number {
  return a + b;
}

// Annotation sur un objet
function afficherProfil(nom: string, age: number): void {
  console.log(`${nom}, ${age} ans`);
}

// Paramètre optionnel avec ?
function saluer(prenom: string, titre?: string): string {
  return titre ? `${titre} ${prenom}` : prenom;
}
